import { useState } from "react";
import axios from "../api/axios";
import { useNavigate } from "react-router-dom";

export default function AdminLogin() {
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [error, setError] = useState("");
    const navigate = useNavigate();

    const handleLogin = async (e) => {
        e.preventDefault();
        try {
            const res = await axios.post("/auth/login", { email, password });
            if (res.data.role === "admin") {
                localStorage.setItem("token", res.data.token);
                localStorage.setItem("role", res.data.role); // Store role
                navigate("/admin");
            } else {
                setError("Access Denied: Admins Only");
            }
        } catch (err) {
            setError(err.response?.data?.message || "Login failed");
        }
    };

    return (
        <div className="auth-container">
            <div className="auth-card">
                <h2 className="auth-title" style={{ color: "var(--accent-pink)", textShadow: "var(--shadow-neon-pink)" }}>🛡️ ACCESS TERMINAL</h2>
                {error && <p style={{ color: 'var(--accent-pink)', textAlign: 'center', background: 'rgba(255, 42, 95, 0.1)', padding: '10px', borderRadius: '5px', border: '1px solid var(--accent-pink)' }}>{error}</p>}
                <form onSubmit={handleLogin} style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
                    <div className="input-group">
                        <input
                            type="email"
                            placeholder="Admin Identifier"
                            value={email}
                            onChange={e => setEmail(e.target.value)}
                            required
                        />
                    </div>
                    <div className="input-group">
                        <input
                            type="password"
                            placeholder="Passcode"
                            value={password}
                            onChange={e => setPassword(e.target.value)}
                            required
                        />
                    </div>
                    <button type="submit" className="btn-primary" style={{ background: "transparent", border: "1px solid var(--accent-pink)", color: "var(--accent-pink)", boxShadow: "0 0 15px rgba(255, 42, 95, 0.3)", marginTop: "10px" }}>
                        INITIALIZE OVERRIDE
                    </button>
                </form>
            </div>
        </div>
    );
}
